def greedy_color(graph):
    colors = {}
    nodes = sorted(list(graph.keys()))

    for node in nodes:
        neighbor_colors = set()
        for neighbor in graph.get(node, []):
            if neighbor in colors:
                neighbor_colors.add(colors[neighbor])

        current_color = 0
        while current_color in neighbor_colors:
            current_color += 1

        colors[node] = current_color

    return colors
